        _threadReply = "";
    }

    private async Task SendThreadReplyAsync()
    {
        if (string.IsNullOrWhiteSpace(_threadReply) || _threadRootMessage is null || _activeChannelId is null)
            return;

        var reply = await ChatService.SendMessageAsync(_activeChannelId.Value, _threadReply.Trim(), _threadRootMessage.Id);
