        {
            < 60 => "just now",
            < 3600 => $"{(int)diff.TotalMinutes} min ago",
            < 86400 => $"{(int)diff.TotalHours}h ago",
            < 604800 => $"{(int)diff.TotalDays}d ago",
            _ => sentAt.ToString("MMM d, yyyy")
        };
    }

    private static string Truncate(string value, int maxLength) =>
        value.Length <= maxLength ? value : value[..(maxLength - 1)] + "…";

    private async Task ScrollToBottom()
    {
        await Task.Yield();
        await JS.InvokeVoidAsync("eval", "(() => { const el = document.querySelector('.message-list'); if(el) el.scrollTop = el.scrollHeight; })()");
    }
}

