arguments.file_text:
/* ── Root layout ── */
::deep .chat-app {
    display: flex;
    height: 100vh;
    font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, sans-serif;
    color: #1a1a2e;
    background: #f0f2f5;
}

/* ── Left Sidebar ── */
::deep .channel-sidebar {
    width: 20%;
    min-width: 200px;
    background: #1a1a2e;
    color: #c4c4d4;
    display: flex;
    flex-direction: column;
    border-right: 1px solid #2a2a4a;
}

::deep .sidebar-header {
    padding: 16px 20px;
    border-bottom: 1px solid #2a2a4a;
}

::deep .sidebar-header h3 {
    margin: 0;
    font-size: 1rem;
    font-weight: 700;
    color: #fff;
    text-transform: uppercase;
    letter-spacing: 0.05em;
}

::deep .channel-list {
    list-style: none;
    margin: 0;
    padding: 8px 0;
    overflow-y: auto;
    flex: 1;
}

::deep .channel-item {
    padding: 10px 20px;
    cursor: pointer;
    position: relative;
    transition: background 0.15s;
}

::deep .channel-item:hover {
    background: rgba(255, 255, 255, 0.06);
}

::deep .channel-item.active {
    background: rgba(99, 102, 241, 0.2);
    border-left: 3px solid #6366f1;
}

::deep .channel-name {
    font-weight: 600;
    font-size: 0.9rem;
    color: #e2e2f0;
}

::deep .channel-item.active .channel-name {
    color: #fff;
}

::deep .channel-desc {
    font-size: 0.75rem;
    color: #8888a8;
    margin-top: 2px;
    white-space: nowrap;
    overflow: hidden;
    text-overflow: ellipsis;
}

::deep .unread-badge {
    position: absolute;
    right: 16px;
    top: 50%;
    transform: translateY(-50%);
    background: #6366f1;
    color: #fff;
    font-size: 0.7rem;
    font-weight: 700;
    padding: 2px 7px;
    border-radius: 10px;
    min-width: 20px;
    text-align: center;
}

/* ── Main Message Area ── */
::deep .message-area {
    width: 55%;
    display: flex;
    flex-direction: column;
    background: #fff;
    transition: width 0.25s ease;
}

::deep .message-area.expanded {
    width: 80%;
}

::deep .message-header {
    padding: 14px 24px;
    border-bottom: 1px solid #e5e7eb;
    background: #fafbfc;
}

::deep .message-header h2 {
    margin: 0;
    font-size: 1.1rem;
    font-weight: 700;
    color: #1a1a2e;
}

::deep .message-header p {
    margin: 4px 0 0;
    font-size: 0.8rem;
    color: #6b7280;
}

::deep .message-list {
    flex: 1;
    overflow-y: auto;
    padding: 16px 24px;
}

::deep .loading-indicator {
    text-align: center;
    color: #9ca3af;
    font-size: 0.8rem;
    padding: 12px;
}

::deep .message-row {
    display: flex;
    align-items: flex-start;
    gap: 8px;
    padding: 6px 8px;
    border-radius: 8px;
    transition: background 0.1s;
    position: relative;
}

::deep .message-row:hover {
    background: #f7f8fa;
}

::deep .message-bubble {
    flex: 1;
    min-width: 0;
}

::deep .message-meta {
    display: flex;
    align-items: baseline;
    gap: 8px;
    margin-bottom: 2px;
}

::deep .author {
    font-weight: 700;
    font-size: 0.88rem;
    color: #1a1a2e;
}

::deep .timestamp {
    font-size: 0.72rem;
    color: #9ca3af;
}

::deep .message-content {
    font-size: 0.9rem;
    line-height: 1.45;
    color: #374151;
    word-break: break-word;
}

/* Reactions */
::deep .reaction-row {
    display: flex;
    flex-wrap: wrap;
    gap: 4px;
    margin-top: 6px;
}

::deep .reaction-badge {
    display: inline-flex;
    align-items: center;
    gap: 3px;
    padding: 2px 8px;
    border-radius: 12px;
    border: 1px solid #e5e7eb;
    background: #f3f4f6;
    font-size: 0.78rem;
    cursor: pointer;
    transition: background 0.15s, border-color 0.15s;
}

::deep .reaction-badge:hover {
    background: #e0e7ff;
    border-color: #6366f1;
}

/* Thread link */
::deep .thread-link {
    background: none;
    border: none;
    color: #6366f1;
    font-size: 0.78rem;
    font-weight: 600;
    cursor: pointer;
    padding: 4px 0 0;
}

::deep .thread-link:hover {
    text-decoration: underline;
}

/* Hover actions */
::deep .message-actions {
    display: flex;
    gap: 4px;
    position: absolute;
    right: 8px;
    top: -4px;
    background: #fff;
    border: 1px solid #e5e7eb;
    border-radius: 6px;
    padding: 2px 4px;
    box-shadow: 0 2px 8px rgba(0, 0, 0, 0.08);
    z-index: 10;
}

::deep .action-btn {
    background: none;
    border: none;
    padding: 4px 8px;
    font-size: 0.78rem;
    cursor: pointer;
    border-radius: 4px;
    white-space: nowrap;
}

::deep .action-btn:hover {
    background: #f3f4f6;
}

/* Emoji picker */
::deep .emoji-picker-wrapper {
    position: relative;
}

::deep .emoji-picker {
    position: absolute;
